'''
Класс для построения графика транзитов на фиксированную дату
'''


import matplotlib.pyplot as plt
from matplotlib.dates import DateFormatter, WeekdayLocator, DayLocator, HourLocator
from astropy.coordinates import AltAz


import numpy as np
from astropy import units as u
from astropy.time import Time


class TimeGraph():
 global solarTwilight
 def __init__(self, SolarTwilight):
  self.SolarTwilight = SolarTwilight
  self.plotBefore()
#  self.plotAfter()

 def plotBefore(self):
  plt.rc('axes', grid=True)
  plt.rc('grid', color='0.75', linestyle='-', linewidth=0.5)
  plt.rc('figure', figsize=(11.69,8.27))
  plt.rc('legend', fontsize=8)
  plt.rc('font', family='monospace')
  fig, self.ax = plt.subplots()
  fig.subplots_adjust(bottom=0.35,right=0.95)



 def plotObject(self, objectOfInterest, transitInfo, observatory, solarTwilight):
  timeVector = np.arange( (solarTwilight['Midnight']-12*u.hour).jd, (solarTwilight['Midnight']+12*u.hour).jd, (15*u.minute).to( u.day ).value )
  timeVector = Time( timeVector, location=observatory["EarthLocation"], format="jd")
  AltAzFrame = AltAz(obstime=timeVector, location=observatory["EarthLocation"])

  obj = objectOfInterest["SkyCoord"].transform_to( AltAzFrame )
  obj = obj.alt.to(u.deg).value
  label =  objectOfInterest.__repr__() + transitInfo.__repr__()
  if transitInfo["middle_z"]<90 and transitInfo["isNight"]:
   plt.plot( timeVector.plot_date, obj, "-", label=label )

   tmp = [ 
   (transitInfo["begin"] , transitInfo["begin_z"] , "|"),
   (transitInfo["middle"], transitInfo["middle_z"], "*"),
   (transitInfo["end"]   , transitInfo["end_z"]   ,"|")
   ]
   for tmpTime, tmpZ, tmpMarker in tmp:
#   AltAzFrameTransit = AltAz(obstime=tmpTime, location=observatory["EarthLocation"])
#   objTransit = objectOfInterest["SkyCoord"].transform_to(AltAzFrameTransit)
#   objTransit = objTransit.alt.to(u.deg).value
#   plt.plot( tmpTime.plot_date, objTransit, tmpMarker, ms=7, color="black")
    plt.plot( tmpTime.plot_date, 90-tmpZ, tmpMarker, ms=7, color="black")


 def plotAfter(self, jpegFileName='tmp'):
  for keyword in [ 'Midnight', 'Astronomical0' , 'Astronomical1', 'Nautical0', 'Nautical1']:
   plt.vlines(self.SolarTwilight[keyword].plot_date, 0, 90, color='0.85', zorder=0, linestyles='dashed')
  plt.ylim(0, 90)
  plt.xlim( (self.SolarTwilight['Nautical0']-1*u.hour).plot_date, (self.SolarTwilight['Nautical1']+1*u.hour).plot_date)
#  plt.title(currentDate)
  

  alldays = DayLocator()
  markhours = HourLocator(interval=1)
  hourFormater =  DateFormatter('%H')  # e.g., 12h
  dayFormater =  DateFormatter('%b %d')  # e.g., Jan 12
  self.ax.xaxis.set_major_locator(markhours)
  self.ax.xaxis.set_minor_locator(alldays)
  self.ax.xaxis.set_major_formatter(hourFormater)
  self.ax.legend( bbox_to_anchor=(0.9, -0.05) )
  plt.savefig( "{}.jpeg".format(jpegFileName))
  plt.clf()


from observatory import Observatory
from sun import SolarTwilight
if __name__ == "__main__":
 observatory = Observatory("saoras")
 solarTwilight = SolarTwilight(observatory, '2026-03-15')
 timeGraph = TimeGraph(solarTwilight)
 timeGraph.plotAfter()
